css:
.section-title {
  border-bottom: 1px solid #b40000;
  padding-bottom: 5px;
  margin-top: 14px;
  margin-bottom: 10px;
  font-weight: 700;
}

/* --- Main (pretty) tables --- */
.form-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 14px;
  table-layout: fixed;
}

.form-table th,
.form-table td {
  padding: 8px;
  font-size: 11pt;
  vertical-align: top;
}

.form-table th {
  background: #f5f5f5;
  border-bottom: 1px solid #ddd;
  text-align: left;
  font-weight: 700;
}

.form-table td {
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

.form-table td:last-child,
.form-table th:last-child {
  border-right: none;
}

.form-table tbody tr:last-child td {
  border-bottom: none;
}

/* --- Signature grids (rounded, matching form-table) --- */
.sig-grid {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  table-layout: fixed;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-top: 10px;
  margin-bottom: 12px;
}

.sig-grid th,
.sig-grid td {
  padding: 8px;
  font-size: 11pt;
  vertical-align: top;
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

.sig-grid th:last-child,
.sig-grid td:last-child {
  border-right: none;
}

.sig-grid tbody tr:last-child th,
.sig-grid tbody tr:last-child td {
  border-bottom: none;
}

.sig-grid th {
  font-weight: 700;
  text-align: center;
  background: #f5f5f5;
}

.sig-rowlabel {
  width: 14%;
  font-weight: 700;
  background: #fff;
}

.small-muted {
  font-size: 10pt;
  color: #666;
  margin-top: 8px;
}

.signatures {
  margin-top: 20px;
  page-break-inside: avoid;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
}

.signatures td {
  width: 50%;
  padding: 18px 24px 14px 0;
  border: none;
  vertical-align: bottom;
}

.signatures td:nth-child(even) {
  padding-right: 0;
}

.signature-space {
  height: 34px;
}

.signature-line {
  width: 100%;
  margin-bottom: 5px;
  border-top: 1px solid #333;
}

.signatures p {
  margin: 0;
  font-size: 9pt;
}

@page {
  margin: 20mm 15mm 25mm 15mm;
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
